prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?task
  ?taskName
  (COUNT(DISTINCT ?mf) AS ?messageFlowCount)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bboExt:initiatingParticipantRef ?partRefStr .
  OPTIONAL { ?task bbo:name ?taskName . }

  # resolve initiating participant ref string to actual Participant element in same choreography
  ?initPart a bboExt:Participant ;
            tai:belongsTo ?choreo .
  FILTER(STRENDS(STR(?initPart), ?partRefStr))

  # count message flows where that participant is sender (as sourceRef) or receiver (as targetRef)
  {
    ?mf a bboExt:MessageFlow ;
        tai:belongsTo ?choreo ;
        bboExt:sourceRef ?pRefStr ;
        bboExt:messageRef ?msg .
    FILTER(STRENDS(STR(?initPart), ?pRefStr))
  }
  UNION
  {
    ?mf a bboExt:MessageFlow ;
        tai:belongsTo ?choreo ;
        bboExt:targetRef ?pRefStr ;
        bboExt:messageRef ?msg .
    FILTER(STRENDS(STR(?initPart), ?pRefStr))
  }
}
GROUP BY ?task ?taskName
HAVING (COUNT(DISTINCT ?mf) > 1)
ORDER BY DESC(?messageFlowCount)
LIMIT 25

